var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"......그렇지.","JPN":"……そうだ。","ENG":"Oh, that's right.","TWN":"……是啊。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"당신이 좀 도와 주면 되겠네요.","JPN":"ちょっと手を貸してください。","ENG":"Perhaps you can help me.","TWN":"還是說你來幫我一下吧。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"네? 제가요?","JPN":"え？　私ですか？","ENG":"Huh? Me?","TWN":"啊？我嗎？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"너무 걱정 마세요. 학위는 수여 받지 못했지만 전 이 분야의 전문가입니다.","JPN":"心配することはありません。学位は取れなかったけど、僕はこの分野の専門家です。","ENG":"Don't worry. I may not actually have a degree, but I'm a leading expert in this field.","TWN":"別太擔心。雖然我沒有獲得學位，但我是這個領域的專家。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"무슨 일이 생기더라도 저만 믿으면 돼요.","JPN":"何が起こっても僕だけを信じれば大丈夫です。","ENG":"No matter what happens, you can trust me.","TWN":"不管發生什麼事，只要相信我就好了。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"현실로 돌아가서 확인하는 게 낫지 않을까요? 무슨 일이 생길지 모르잖아요?","JPN":"現実世界に戻って確認したほうがいいんじゃないですか？　何が起こるかわかりませんよ？","ENG":"Don't you think it's better to check back on the Normalside? You never know what could go wrong.","TWN":"回到現實世界再確認是不是更好一點？畢竟不知道會發生什麼。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"......그래선 늦어요.","JPN":"……それでは間に合いません。","ENG":"It'll be too late by then.","TWN":"……那樣就晚了。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"저 돈에 미친 사채업자가 이터니움만 받고 곱게 손을 뗄 리 없습니다.","JPN":"あの金に狂った闇金業者が、エタニウムだけ引き取ってあっさり手を引くはずがありません。","ENG":"No amount of Eternium will be enough to satisfy that money-grubbing loan shark.","TWN":"那些眼裡只有錢的放貸者不可能只滿足於永恆之金。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"개인적인 호기심도 있지만...... 지금 확인해 둬야 해요.","JPN":"個人的な好奇心もありますが……今確認しておかなければなりません。","ENG":"Granted, I'm partially driven by personal curiosity too... but it's vital that we check now.","TWN":"當然也是因為我很好奇……必須現在確認。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"하지만......","JPN":"ですが……","ENG":"But...","TWN":"但是……"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"으앗!?","JPN":"うわっ！","ENG":"Eek?","TWN":"呃啊！？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"하하, 미안합니다. 학문에는 원래 도전이 필요하거든요.","JPN":"ハハ、ごめんなさい。学問は挑戦することが大事なんです。","ENG":"Hah hah, sorry about that. But the pursuit of knowledge always involves taking chances.","TWN":"哈哈，對不起。追求學問本來就需要勇於挑戰。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"까, 깜짝 놀랐어요!","JPN":"び、びっくりしました！","ENG":"Y-you scared me!","TWN":"嚇、嚇我一大跳！"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"괜찮아요. 아직 아무 일도 벌어지지 않았잖습니까.","JPN":"大丈夫ですよ。まだ何も起きていないじゃないですか。","ENG":"It's okay. Nothing's happened yet.","TWN":"沒關係，現在不是什麼事也沒發生嗎。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"하지만 카운터를 상대로는 사진이 찍히네요.","JPN":"しかし、カウンターが被写体だと写真が撮れるんですね。","ENG":"But now I know the camera works on Counters at least.","TWN":"但以制裁者為對象還可以拍照。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"역시 평범한 잡동사니일 리 없지...... 그래, 무식한 놈들이 뭘 알겠어......","JPN":"やはり普通のがらくたのはずがない……そうさ、無知な輩に何がわかる……","ENG":"I knew this wasn't just a piece of junk... Of course those ignorant fools didn't know what they were talking about...","TWN":"果然不是一般的東西……沒錯，那些廢物懂什麼……"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"어디 보자...... 폴라로이드 카메라인데 필름은 들어 있지 않고......","JPN":"どれどれ……インスタントカメラなのにフィルムは入ってないのか……","ENG":"Let’s see... It's an instant camera, but it doesn't have any film inside...","TWN":"讓我看看……這是拍立得相機，但裡面沒有膠捲……"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};